const seed = { ...$json };
const issueKey = String(seed.issueKey || '').trim().toUpperCase();
if (!/^(SIS|REC)-\d+$/.test(issueKey)) throw new Error(`issueKey inválido: ${issueKey || '(vacío)'}`);
for (const required of ['jiraBaseUrl', 'jiraApiVersion']) {
  if (!String(seed[required] || seed.context?.[required] || '').trim()) throw new Error(`Falta ${required} para ${issueKey}`);
}
const context = { ...(seed.context || {}), ...seed };
return { json: { ...seed, issueKey, jiraBaseUrl: context.jiraBaseUrl, jiraApiVersion: context.jiraApiVersion, jiraPageSize: Math.min(Math.max(Number(context.jiraPageSize || 100),1),100) } };

const rows = $input.all().map((item) => item.json).filter((row) => row.issueKey);
const byKey = new Map();
for (const row of rows) {
  if (!byKey.has(row.issueKey)) byKey.set(row.issueKey, []);
  byKey.get(row.issueKey).push(row);
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function decodeHtmlEntities(text) {
  return String(text || '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/&amp;/gi, '&')
    .replace(/&lt;/gi, '<')
    .replace(/&gt;/gi, '>')
    .replace(/&quot;/gi, '"')
    .replace(/&#39;/gi, "'")
    .replace(/&#160;/gi, ' ')
    .replace(/&#x27;/gi, "'")
    .replace(/&#x2F;/gi, '/');
}

function stripHtml(text) {
  return decodeHtmlEntities(String(text || ''))
    .replace(/<style\b[^>]*>[\s\S]*?<\/style>/gi, ' ')
    .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, ' ')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/li>/gi, '\n')
    .replace(/<li\b[^>]*>/gi, '- ')
    .replace(/<[^>]+>/g, ' ');
}

function allText(value, out = []) {
  if (value == null) return out;
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    out.push(stripHtml(String(value)));
    return out;
  }
  if (Array.isArray(value)) {
    value.forEach((v) => allText(v, out));
    return out;
  }
  if (typeof value === 'object') {
    if (typeof value.text === 'string') out.push(stripHtml(value.text));
    for (const [key, nested] of Object.entries(value)) {
      if (key === 'text') continue;
      allText(nested, out);
    }
  }
  return out;
}

function plainText(value, max = 8000) {
  const text = allText(value)
    .join(' ')
    .replace(/\r/g, '')
    .replace(/\bSubtareas\b[\s\S]*$/i, '')
    .replace(/\bActividades vinculadas\b[\s\S]*$/i, '')
    .replace(/\bAnadir subtarea\b/gi, '')
    .replace(/\bA?adir subtarea\b/gi, '')
    .replace(/\bAnadir actividad vinculada\b/gi, '')
    .replace(/\bA?adir actividad vinculada\b/gi, '')
    .replace(/[\t ]+/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .replace(/ ?\n ?/g, '\n')
    .trim();
  if (!text) return null;
  return text.length > max ? text.slice(0, max).trim() + '...' : text;
}

function actorName(value) {
  if (!value) return null;
  if (typeof value === 'string') return plainText(value, 300);
  return plainText(
    value.displayName || value.name || value.emailAddress || value.key || value.accountId || value.login || value.username || '',
    300
  );
}

function refs(value, prefix) {
  const r = new RegExp('\\b' + prefix + '[\\s_-]*(\\d+)\\b', 'gi');
  const keys = new Set();
  for (const text of allText(value)) {
    for (const match of text.matchAll(r)) keys.add(prefix + '-' + match[1]);
  }
  return [...keys];
}

function pageItems(pages, candidates) {
  const result = [];
  for (const page of pages) {
    const source = page?.values || candidates.map((key) => page?.[key]).find(Array.isArray) || [];
    result.push(...source);
  }
  const seen = new Set();
  return result.filter((value) => {
    const key = value?.id || JSON.stringify(value);
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}

function normalizeFieldName(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[̀-ͯ]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, ' ')
    .trim();
}

function namedFieldText(issue, fieldName) {
  const names = issue?.names || {};
  const fields = issue?.fields || {};
  const renderedFields = issue?.renderedFields || {};
  const target = normalizeFieldName(fieldName);
  const candidates = Object.entries(names).filter(([_, displayName]) => {
    const current = normalizeFieldName(displayName);
    return current === target || current.includes(target) || target.includes(current);
  });
  for (const [fieldKey] of candidates) {
    const rendered = plainText(renderedFields[fieldKey], 12000);
    if (rendered) return rendered;
    const raw = plainText(fields[fieldKey], 12000);
    if (raw) return raw;
  }
  return null;
}

return [...byKey.entries()].map(([issueKey, group]) => {
  const seed = group[0].seed || {};
  const issue = group.find((r) => r.recordType === 'issue')?.payload || {};
  const fields = issue.fields || {};
  const worklogs = pageItems(group.filter((r) => r.recordType === 'worklogsPage').map((r) => r.payload), ['worklogs']);
  const changelog = pageItems(group.filter((r) => r.recordType === 'changelogPage').map((r) => r.payload), ['histories']);

  const links = asArray(fields.issuelinks).map((link) => {
    const related = link.outwardIssue || link.inwardIssue;
    if (!related?.key) return null;
    return {
      key: String(related.key).toUpperCase(),
      relation: plainText(link.type?.name || '', 300) || null,
      direction: link.outwardIssue ? 'outward' : 'inward',
      source: 'issueLink',
      summary: plainText(related.fields?.summary || '', 800) || null,
    };
  }).filter(Boolean);

  const all = { fields, renderedFields: issue.renderedFields || {}, worklogs, changelog };
  const own = String(issueKey).toUpperCase();
  const relatedSisKeys = [...new Set([...links.filter((link) => /^SIS-\d+$/.test(link.key)).map((link) => link.key), ...refs(all, 'SIS').filter((key) => key !== own)])];
  const recKeys = [...new Set([...links.filter((link) => /^REC-\d+$/.test(link.key)).map((link) => link.key), ...refs(all, 'REC')])];
  const limit = Number(seed.maxStoredIssueDescriptionChars || 8000);
  const description = plainText(issue.renderedFields?.description || fields.description, limit) || null;
  const readme = plainText(namedFieldText(issue, 'README') || '', limit) || null;
  const errors = group.filter((row) => row.payload && !row.payload.fields && (row.payload.error || row.payload.message)).map((row) => ({
    source: row.recordType,
    message: plainText(row.payload.message || row.payload.error || '', 1000),
    statusCode: row.payload.statusCode || row.payload.code || null,
  }));

  return {
    json: {
      kind: 'issueRecord',
      role: seed.role || 'unknown',
      issueKey: own,
      context: seed.context || {},
      originCommitShas: seed.originCommitShas || [],
      relatedFrom: seed.relatedFrom || [],
      issue: {
        key: own,
        browseUrl: String(seed.jiraBaseUrl || '').replace(/\/$/, '') + '/browse/' + own,
        fetchStatus: issue.fields ? 'retrieved' : (errors.length ? 'failedOrMissing' : 'notRetrieved'),
        normalized: {
          summary: plainText(fields.summary || '', 1500) || null,
          issueType: plainText(fields.issuetype?.name || '', 300) || null,
          status: plainText(fields.status?.name || '', 300) || null,
          resolution: plainText(fields.resolution?.name || '', 300) || null,
          priority: plainText(fields.priority?.name || '', 300) || null,
          assignee: actorName(fields.assignee),
          reporter: actorName(fields.reporter),
          labels: asArray(fields.labels).map((value) => plainText(value, 300)).filter(Boolean),
          components: asArray(fields.components).map((value) => plainText(value?.name || value, 300)).filter(Boolean),
          fixVersions: asArray(fields.fixVersions).map((value) => plainText(value?.name || value, 300)).filter(Boolean),
          description,
          descriptionText: description,
          descriptionTruncated: Boolean(description && description.length >= limit),
          readme,
        },
        relationships: {
          linkedIssues: links,
          relatedSisKeys,
          recKeys,
        },
        evidence: {
          comments: [],
          activityScanned: {
            comments: 0,
            worklogs: worklogs.length,
            changelog: changelog.length,
          },
        },
        rawIssue: issue,
      },
      fetchErrors: errors,
    },
  };
});
